function calculate({ populationSize, baselineAnnualIncidenceRate, policyInterventionCoverage, policyEfficacyReductionRate, policyDurationYears, avgTreatmentCostPerCase, avgQALYLossPerCase, healthcareSystemMaxCapacityCases }) {

  // Input validation and normalization
  populationSize = Math.max(0, populationSize || 0);
  baselineAnnualIncidenceRate = Math.max(0, Math.min(100, baselineAnnualIncidenceRate || 0)); // 0-100%
  policyInterventionCoverage = Math.max(0, Math.min(100, policyInterventionCoverage || 0)); // 0-100%
  policyEfficacyReductionRate = Math.max(0, Math.min(100, policyEfficacyReductionRate || 0)); // 0-100%
  policyDurationYears = Math.max(0, policyDurationYears || 0);
  avgTreatmentCostPerCase = Math.max(0, avgTreatmentCostPerCase || 0);
  avgQALYLossPerCase = Math.max(0, avgQALYLossPerCase || 0);
  healthcareSystemMaxCapacityCases = Math.max(1, healthcareSystemMaxCapacityCases || 1); // Ensure no division by zero, min 1 capacity

  // Define a value for one QALY for economic benefit calculation (can be an input in advanced versions)
  const valuePerQALY = 50000; // Common benchmark for QALY valuation

  // 1. Calculate annual baseline cases without any policy
  const annualBaselineCases = populationSize * (baselineAnnualIncidenceRate / 100);

  // Handle cases where policy duration is 0, or no efficacy/coverage
  if (policyDurationYears === 0) {
    const annualCasesAfterPolicy = annualBaselineCases;
    const strainIndex = Math.min(100, Math.max(0, (annualCasesAfterPolicy / healthcareSystemMaxCapacityCases) * 100));
    return {
      projectedCasesAvoidedTotal: 0,
      cumulativeHealthcareCostSavings: 0,
      totalQALYsGained: 0,
      avgAnnualHealthcareSystemStrainIndex: parseFloat(strainIndex.toFixed(1)),
      netHealthEconomicBenefit: 0
    };
  }

  // 2. Calculate annual cases avoided due to policy efficacy and coverage
  const coveredPopulation = populationSize * (policyInterventionCoverage / 100);
  const potentialCasesInCoveredPopAnnually = coveredPopulation * (baselineAnnualIncidenceRate / 100);
  const annualCasesAvoided = potentialCasesInCoveredPopAnnually * (policyEfficacyReductionRate / 100);

  // 3. Calculate total projected cases avoided over the policy duration
  const projectedCasesAvoidedTotal = annualCasesAvoided * policyDurationYears;

  // 4. Calculate cumulative healthcare cost savings
  const cumulativeHealthcareCostSavings = projectedCasesAvoidedTotal * avgTreatmentCostPerCase;

  // 5. Calculate total QALYs gained
  const totalQALYsGained = projectedCasesAvoidedTotal * avgQALYLossPerCase;

  // 6. Calculate average annual healthcare system strain index
  // Annual cases after policy implementation
  const annualCasesAfterPolicy = annualBaselineCases - annualCasesAvoided;
  // Ensure annualCasesAfterPolicy doesn't go negative for strain calculation; floor at 0.
  const casesForStrainCalculation = Math.max(0, annualCasesAfterPolicy);
  const avgAnnualHealthcareSystemStrainIndex = Math.min(100, Math.max(0, (casesForStrainCalculation / healthcareSystemMaxCapacityCases) * 100));

  // 7. Calculate net health economic benefit (cost savings + monetary value of QALYs gained)
  const netHealthEconomicBenefit = cumulativeHealthcareCostSavings + (totalQALYsGained * valuePerQALY);

  return {
    projectedCasesAvoidedTotal: Math.round(projectedCasesAvoidedTotal),
    cumulativeHealthcareCostSavings: Math.round(cumulativeHealthcareCostSavings),
    totalQALYsGained: parseFloat(totalQALYsGained.toFixed(2)),
    avgAnnualHealthcareSystemStrainIndex: parseFloat(avgAnnualHealthcareSystemStrainIndex.toFixed(1)),
    netHealthEconomicBenefit: Math.round(netHealthEconomicBenefit)
  };
}
